export const JENIS_ORDER_LABELS: Record<number, string> = {
  1: "Couple",
  2: "Single Pria",
  3: "Single Wanita",
};

export function produkInfo(id: unknown): ProdukInfo | null {
  if (id == null || id === "") return null;
  const num = Number(id);
  if (!Number.isFinite(num)) return null;
  return (
    PRODUK_LABELS[num] ?? { nama: `Produk #${num}`, sku: null, spesifikasi: null }
  );
}

export function jenisOrderLabel(id: unknown): string | null {
  if (id == null || id === "") return null;
  const num = Number(id);
  if (!Number.isFinite(num)) return null;
  return JENIS_ORDER_LABELS[num] ?? null;
}
